import uuid

class WorkflowState:
    def __init__(self):
        self.execution_id = str(uuid.uuid4())
        self.steps = []
        self.can_rollback = True

    def record_step(self, step_name: str, result: dict):
        self.steps.append({"step": step_name, "result": result, "idempotent": True})

    def safe_rollback(self, step_index: int):
        if self.can_rollback and step_index < len(self.steps):
            step = self.steps[step_index]
            if step["idempotent"]:
                # Execute compensating transaction
                print(f"Rolling back {step['step']}")
                return True
        return False

state = WorkflowState()

