@vex.action_hook(permissions=["api:write", "workflow:execute"])
def verify_api_action(action: dict, context: WorkflowState) -> bool:
    # Check action correctness
    if action["type"] == "api_call":
        required_fields = ["endpoint", "method", "payload"]
        if not all(action.get(f) for f in required_fields):
            vex.block("missing-required-fields")
            return False

        # Idempotency check
        if not context.is_idempotent(action["endpoint"]):
            vex.block("non-idempotent-action")
            return False

    # Permission validation
    result = vex.verify_action(action, context=context.execution_id)
    return result.approved

@vex.decision_hook(decision_type="human-approval")
def guard_human_approval(decision: str, evidence: dict) -> dict:
    if decision == "approved" and evidence.get("amount", 0) > 1000:
        vex.enforce_policy([
            "multi-factor-approval",
            "audit-log-required",
            "rollback-enabled"
        ])

    # Rollback capability verification
    if decision == "rollback":
        rollback_result = state.safe_rollback(evidence["step_index"])
        if not rollback_result:
            vex.block("rollback-failed")
            return {"status": "blocked", "reason": "non-recoverable"}

    return vex.approve_decision(decision, evidence)
